document.addEventListener('DOMContentLoaded', () => {
    const checkbox = document.getElementById('checkboxOption');
    const statusIndicator = document.getElementById('statusIndicator');

    function updateStatusIndicator(isEnabled) {
        statusIndicator.textContent = isEnabled ? 'Status: Enabled' : 'Status: Disabled';
        statusIndicator.className = `status-indicator ${isEnabled ? 'status-enabled' : 'status-disabled'}`;
    }

    // Load the saved state from storage
    chrome.storage.sync.get(['onPageDownload'], function(result) {
        const isEnabled = result.onPageDownload || false;
        checkbox.checked = isEnabled;
        updateStatusIndicator(isEnabled);
    });

    // Save the state whenever the checkbox is toggled
    checkbox.addEventListener('change', async () => {
        await chrome.storage.sync.set({onPageDownload: checkbox.checked});
        updateStatusIndicator(checkbox.checked);
    });
});